/* style.css */

/* Mobile-first: links stack vertically */
.nav {
  display: flex;
  flex-direction: column;
  background: #f0f4ff;
}

.nav a {
  display: block;
  padding: 0.75rem 1rem;
  text-decoration: none;
  color: #1a1a2e;
  font-family: sans-serif;
  border-bottom: 1px solid #d0d8f0;
}

.nav a:hover {
  background: #dce8ff;
}

/* 640 px and up: links in a horizontal row */
@media (min-width: 640px) {
  .nav {
    flex-direction: row;
    align-items: center;
  }

  .nav a {
    border-bottom: none;
    border-right: 1px solid #d0d8f0;
  }
}
